import { type PropsWithChildren, useRef } from 'react';

import { createStore, type Store } from '@dynatrace/strato-components/core';

import { initialState, MapStore } from './map-store.context.js';
import type { MapState } from '../types/state.js';

export const MapStoreProvider = ({ children }: PropsWithChildren) => {
  const storeRef = useRef<Store<MapState> | null>(null);

  storeRef.current ||= createStore(initialState);

  return (
    <MapStore.Provider value={storeRef.current}>{children}</MapStore.Provider>
  );
};
